#
# Structure for table "proprietarios_tabulares"
#

CREATE TABLE `proprietarios_tabulares` (
  `id_tab` int(11) NOT NULL AUTO_INCREMENT,
  `tab_tipo` varchar(30) DEFAULT 'Proprietário',
  `id_tab_procedimento` varchar(20) DEFAULT NULL,
  `tab_desmembramento` varchar(10) DEFAULT NULL,
  `tab_identificado` varchar(30) DEFAULT NULL,
  `tipo_pessoa` varchar(20) DEFAULT NULL,
  `cpf` varchar(30) DEFAULT NULL,
  `tab_falecido` varchar(20) DEFAULT NULL,
  `cnpj` varchar(20) DEFAULT NULL,
  `i_estadual` varchar(30) DEFAULT NULL,
  `i_municipal` varchar(30) DEFAULT NULL,
  `representante` varchar(60) DEFAULT NULL,
  `cargo` varchar(60) DEFAULT NULL,
  `nome` varchar(120) DEFAULT NULL,
  `data_nasc` varchar(20) DEFAULT NULL,
  `sexo` varchar(20) DEFAULT NULL,
  `rg` varchar(20) DEFAULT NULL,
  `emissor` varchar(20) DEFAULT NULL,
  `profissao` varchar(255) DEFAULT NULL,
  `estado_civil` varchar(30) DEFAULT NULL,
  `uniao_estavel` varchar(10) DEFAULT NULL,
  `telefone` varchar(20) DEFAULT NULL,
  `celular` varchar(20) DEFAULT NULL,
  `email` varchar(70) DEFAULT NULL,
  `cep` varchar(20) DEFAULT NULL,
  `logradouro` varchar(150) DEFAULT NULL,
  `numero` varchar(10) DEFAULT NULL,
  `complemento` varchar(60) DEFAULT NULL,
  `bairro` varchar(80) DEFAULT NULL,
  `cidade` varchar(80) DEFAULT NULL,
  `estado` varchar(30) DEFAULT NULL,
  `pai` varchar(150) DEFAULT NULL,
  `mae` varchar(150) DEFAULT NULL,
  `data_cadastro` varchar(20) DEFAULT NULL,
  `data_update` varchar(20) DEFAULT NULL,
  `status_tab` int(11) DEFAULT '1',
  `capacidade` varchar(30) DEFAULT NULL,
  `conjuge_nome` varchar(80) DEFAULT NULL,
  `conjuge_regime` varchar(80) DEFAULT NULL,
  `conjuge_data_casamento` varchar(20) DEFAULT NULL,
  `conjuge_cpf` varchar(20) DEFAULT NULL,
  `conjuge_nasc` varchar(20) DEFAULT NULL,
  `conjuge_sexo` varchar(20) DEFAULT NULL,
  `conjuge_rg` varchar(20) DEFAULT NULL,
  `conjuge_emissor` varchar(20) DEFAULT NULL,
  `conjuge_profissao` varchar(60) DEFAULT NULL,
  `conjuge_estado_civil` varchar(20) DEFAULT NULL,
  `conjuge_telefone` varchar(20) DEFAULT NULL,
  `conjuge_celular` varchar(20) DEFAULT NULL,
  `conjuge_email` varchar(60) DEFAULT NULL,
  `conjuge_cep` varchar(15) DEFAULT NULL,
  `conjuge_log` varchar(50) DEFAULT NULL,
  `conjuge_numero` varchar(12) DEFAULT NULL,
  `conjuge_complemento` varchar(30) DEFAULT NULL,
  `conjuge_bairro` varchar(35) DEFAULT NULL,
  `conjuge_municipio` varchar(35) DEFAULT NULL,
  `conjuge_estado` varchar(30) DEFAULT NULL,
  `conjuge_pai` varchar(60) DEFAULT NULL,
  `conjuge_mae` varchar(60) DEFAULT NULL,
  `conjuge_update` varchar(20) DEFAULT NULL,
  `conjuge_capacidade` varchar(30) DEFAULT NULL,
  PRIMARY KEY (`id_tab`)
) ENGINE=InnoDB AUTO_INCREMENT=411 DEFAULT CHARSET=utf8mb4 ROW_FORMAT=DYNAMIC;

