#
# Structure for table "tb_etapa_historico"
#

CREATE TABLE `tb_etapa_historico` (
  `h_id` int(11) NOT NULL AUTO_INCREMENT,
  `h_statusID` varchar(30) DEFAULT NULL,
  `h_idProcesso` varchar(20) DEFAULT NULL,
  `h_name` varchar(255) DEFAULT NULL,
  `h_justificativa` text,
  `h_date` datetime DEFAULT NULL,
  `h_status` int(11) DEFAULT '1',
  `h_user` int(11) DEFAULT NULL,
  PRIMARY KEY (`h_id`)
) ENGINE=InnoDB AUTO_INCREMENT=158 DEFAULT CHARSET=utf8mb4;

