#
# Structure for table "tb_etapas_anexos"
#

CREATE TABLE `tb_etapas_anexos` (
  `anexo_id` int(11) NOT NULL AUTO_INCREMENT,
  `anexo_prc` varchar(15) DEFAULT NULL,
  `anexo_etapa` int(11) DEFAULT NULL,
  `anexo_titulo` varchar(255) DEFAULT NULL,
  `anexo_conteudo` longtext,
  `anexo_arquivo` varchar(100) DEFAULT NULL,
  `anexo_arquivo_ext` varchar(10) DEFAULT NULL,
  `anexo_status` int(11) DEFAULT '1',
  `anexo_cadastro` datetime DEFAULT NULL,
  `anexo_user` int(11) DEFAULT NULL,
  `anexo_update` datetime DEFAULT NULL,
  `anexo_ordem` int(11) DEFAULT NULL,
  PRIMARY KEY (`anexo_id`)
) ENGINE=InnoDB AUTO_INCREMENT=90 DEFAULT CHARSET=utf8mb4 ROW_FORMAT=DYNAMIC;

