INSERT INTO `tb_etapas_anexos` VALUES (1,'5828058872',1,'req. abertura',NULL,'32695165-req._abertura.pdf','pdf',1,'2024-12-10 08:37:00',75,NULL,6),(2,'5828058872',2,'matriculas',NULL,'1414149454-matriculas.pdf','pdf',1,'2024-12-10 08:45:59',75,NULL,5),(3,'5828058872',6,'PROJETO','<!DOCTYPE html>\n<html>\n\n<head>\n    <meta charset=\"UTF-8\">\n    <title>PROJETO</title>\n    <style>\n        body {\n            font-family: Arial, sans-serif;\n            font-size: 12px;\n            line-height: 1.6;\n        }\n\n        h1 {\n            text-align: center;\n            color: #555555;\n        }\n\n        p {\n            text-align: justify;\n        }\n\n        i {\n            font-style: italic;\n            font-size: 11px;\n        }\n    </style>\n</head>\n\n<body>\n\n    <div style=\"text-align: center;\">\n        <img src=\"https://e-reurbsistema.com.br/sistema/v2/assets/tema/images/logo_1733236656.png\" alt=\"Logo do Município\" style=\"width: 150px; height: auto;\">\n    </div>\n    <br>\n\n    <h2 style=\"text-align: center; text-transform: uppercase;\">PROGRAMA DE REGULARIZAÇÃO FUNDIÁRIA DE INTERESSE SOCIAL\n        DA PREFEITURA MUNICIPAL DE\n        Juruaia/MG</h2>\n    <h2 style=\"text-align: center; text-transform: uppercase;\">PRF – PROJETO DE REGULARIZAÇÃO FUNDIÁRIA – REURB –\n        “Bairro Nova Resende” PROCESSO\n        ADMINISTRATIVO S2024-003\n    </h2>\n    <br>\n\n\n    <p>\n        Certificamos que o Projeto de Regularização Fundiária está sendo emitido em anexo, considerando as\n        características da ocupação e da área ocupada, onde foi definido parâmetros urbanísticos e ambientais\n        específicos, além de identificar os lotes, as vias de circulação, bem como todas exigências do art. 35 e seus\n        incisos, da Lei 13.465 de 11 de julho de 2017.</p>\n    <p>\n       <strong>Equipe técnica e de apoio:</strong> \n    </p>\n    <p>\n        \n            <ul>\n              <li><b>Taize Marcelino Martins Costa</b> - Presidente da Comissão</li>\n            </ul>\n              \n            <ul>\n              <li><b>Carlos Alberto de Souza Junior</b> - Secretário Municipal de Obras e Serviços Urbanos</li>\n            </ul>\n              \n            <ul>\n              <li><b>Luciana Salomão Baroni</b> - Arquiteta</li>\n            </ul>\n              \n            <ul>\n              <li><b>Dr. Maurício Macedo</b> - Assessor Jurídico</li>\n            </ul>\n              \n            <ul>\n              <li><b>Gustavo Pereira Andrade</b> - Procurador Geral – Advogado OAB/MG 140.207</li>\n            </ul>\n              \n            <ul>\n              <li><b>Eloy Arraes Branco Avelino</b> - Coordenador de Convênios e Contratos</li>\n            </ul>\n              \n            <ul>\n              <li><b>Giseli Trindade Bueno</b> - Controladoria Interna</li>\n            </ul>\n              \n            <ul>\n              <li><b>Edilberto Baquião da Silva</b> - Engenheiro Civil – CREA-MG 64.575/D</li>\n            </ul>\n              \n            <ul>\n              <li><b>Celso Marques Júnior </b> - Prefeito Municipal</li>\n            </ul>\n              \n            <ul>\n              <li><b>Ana Paula Jacó</b> - Secretário Municipal de Urbanismo e Meio Ambiente</li>\n            </ul>\n              \n    </p>\n    <br>\n    <br>\n\n    <p style=\"text-align: center;\">\n        Juruaia - MG, 13 de dezembro de 2024\n    </p>\n    <p style=text-align:center>Celso Marques Junior<br>Prefeito Municipal</p>\n\n</body>\n\n</html>','projeto_81652951.pdf','pdf',1,'2024-12-13 08:33:48',75,NULL,4),(4,'5828058872',7,'CRF','<!DOCTYPE html>\n<html>\n\n<head>\n    <meta charset=\"UTF-8\">\n    <title>CRF</title>\n    <style>\n        body {\n            font-family: Arial, sans-serif;\n            font-size: 12px;\n            line-height: 1.6;\n        }\n\n        h1 {\n            text-align: center;\n            color: #555555;\n        }\n\n        p {\n            text-align: justify;\n        }\n\n        i {\n            font-style: italic;\n            font-size: 11px;\n        }\n    </style>\n</head>\n\n<body>\n\n    <div style=\"text-align: center;\">\n        <img src=\"https://e-reurbsistema.com.br/sistema/v2/assets/tema/images/logo_1733236656.png\" alt=\"Logo do Município\" style=\"width: 150px; height: auto;\">\n    </div>\n\n    <h1>CERTIDÃO DE REGULARIZAÇÃO FUNDIÁRIA</h1>\n\n    <p><strong>Número do procedimento:</strong> S2024-003</p>\n    <p><strong>Modalidade:</strong> Reurb-S</p>\n    <p><strong>Tipo:</strong> COLETIVO</p>\n\n    <p>\n        Eu, <b>Celso Marques Junior</b>, inscrito no CNPF/MF sob o nº <i>111.111.111-11</i>, portador da cédula\n        de identidade Registro Geral nº <i>rg</i>, <b>Prefeito Municipal de Juruaia</b>, em pleno\n        exercício do mandato,\n        na forma da Lei e nos termos dos Artigos 30 e 41 da Lei Federal nº 13.465/2017, do Art. 38 do Decreto nº\n        9.310/2018, e Lei Complementar Municipal nº <i>99.99</i> e Decreto Municipal nº\n        <i>99</i>, <b>CERTIFICO</b> para os devidos fins de registro imobiliário, que tramitou\n        perante a Comissão Municipal de Regularização Fundiária, nomeada pelo Decreto <i>99</i>.\n        O Procedimento Administrativo Nº S2024-003 requerido pela Comissão de Regularização Fundiária\n        Urbana de Juruaia, através de sua presidente, <i>{presidente}</i>, teve início através da Portaria\n        nº <i>{portaria}</i> de <i>{dia}</i> de <i>{mes}</i> de <i>{ano}</i>, procedimento\n        ora finalizado por decisão da Comissão, emitindo o Projeto completo, conforme em anexo, que acato e defiro,\n        informando os seguintes requisitos existentes no referido procedimento:\n    </p>\n\n    <p>\n        1 - <b>Nome do núcleo:</b> Bairro Nova Resende <br>\n        2 - <b>Localização:</b> <br>\n        3 - <b>Memorial Descritivo:</b><br><i></i><br>\n        4 - <b>Modalidade da Regularização:</b> Reurb-S<br>\n        5 - <b>Projeto Técnico da Regularização:</b> Segue em anexo, assinado pelo engenheiro responsável e pela equipe\n        da Reurb Juruaia<br>\n        6 - O Núcleo informal passa a fazer parte da área urbana do município, eis que já dentro do perímetro urbano\n        conforme Lei Municipal 99<br>\n        7 - <b>Da responsabilidade das obras e serviços constantes do cronograma:</b><br>\n        Conforme certidão de cronograma na forma do Art. 41, IV da Lei 13.465/17, será do poder público municipal,\n        através de recursos próprios ou de convênios, repasses específicos\n        ou outra forma, a implementação do restante da infraestrutura faltante no núcleo, a saber, energia elétrica,\n        meio-fio, esgoto e pavimentação (podendo ser asfáltica ou outra modalidade),\n        que, considerando haver possibilidade de regularização posterior individual via Reurb-S, poderá ter auxílio dos\n        ocupantes, tudo no prazo do {§1º} do Art. {} da Lei Complementar\n        Municipal 99.99, ou programas próprios ou dos governos federal e estadual.<br>\n\n        8 - <b>Lotes Regularizados:</b> Os lotes regularizados são os que fazem parte do memorial descritivo, aprovado\n        no projeto de regularização em anexo, resumidamente a saber:<br>\n    </p>\n\n    <ul>\n        <li><b>Quadra: B</b></li>\n            <ul>\n              <li>\n                 <b>Lote: 1</b> - Proprietário(s): <b>JUSCELIO FERNANDO NOVAIS</b>\n                 <br>\n                 <b>Memorial descritivo:</b> <i>memorial</i>\n              </li>\n              <hr>\n            </ul>\n            <ul>\n              <li>\n                 <b>Lote: 2</b> - Proprietário(s): <b>JUSCELIO FERNANDO NOVAIS, PAULO CESAR PEREIRA ALVES</b>\n                 <br>\n                 <b>Memorial descritivo:</b> <i></i>\n              </li>\n              <hr>\n            </ul><li><b>Quadra: C</b></li>\n            <ul>\n              <li>\n                 <b>Lote: 1</b> - Proprietário(s): <b>JUSCELIO FERNANDO NOVAIS</b>\n                 <br>\n                 <b>Memorial descritivo:</b> <i>memorial</i>\n              </li>\n              <hr>\n            </ul>\n            <ul>\n              <li>\n                 <b>Lote: 2</b> - Proprietário(s): <b>Sem proprietário</b>\n                 <br>\n                 <b>Memorial descritivo:</b> <i>memorial</i>\n              </li>\n              <hr>\n            </ul>\n    </ul>\n\n    <br>\n    <p><b>PROPRIETÁRIOS:</b></p>\n    <p>\n        <p style=\'text-align: justify;\'><b>Proprietário:</b> JUSCELIO FERNANDO NOVAIS, CPF: 079.868.986-23, RG: {não informado}, \n        Profissão: {não informado}, Nascido em: {não informado} (menor de idade), \n        Filho de {não informado} e {não informado}, Estado Civil: Casado, \n        Residente no endereço: {não informado}, {não informado} {não informado}, \n        Bairro: {não informado}, Cidade: {não informado}, Estado: {não informado}, \n        CEP: {não informado}, Capacidade: {não informado}.</p>\n            <p style=\'text-align: justify;\'><b>Cônjuge:</b> nome do conjuge, CPF: 113.637.996-73, RG: {não informado}, \n            Profissão: {não informado}, Nascido em: {não informado} (menor de idade), \n            Filho de {não informado} e {não informado}.</p><hr>\n        <p style=\'text-align: justify;\'><b>Proprietário:</b> PAULO CESAR PEREIRA ALVES, CPF: 113.637.996-73, RG: {não informado}, \n        Profissão: {não informado}, Nascido em: {não informado} (menor de idade), \n        Filho de {não informado} e {não informado}, Estado Civil: {não informado}, \n        Residente no endereço: {não informado}, {não informado} {não informado}, \n        Bairro: {não informado}, Cidade: {não informado}, Estado: {não informado}, \n        CEP: {não informado}, Capacidade: {não informado}.</p><hr></p>\n    <br>\n\n    <p>9 - A presente Certidão vai acompanhada dos seguintes documentos: Projeto da\n        Regularização, Memorial descritivo\n        das Quadras, Mapas geográficos, 1 via do ART e principais\n        documentos do processo administrativo.</p>\n\n    <p>10 - Conforme Art. 22, §6º da Lei 13.465/17, a área remanescente da matrícula do\n        imóvel atingido deve ser apurada\n        e realizada a retificação por responsabilidade de seus proprietários.</p>\n\n    <p>11 - Conclui-se, portanto, e certifico que a poligonal parcial definida como\n        \"Bairro Nova Resende\" está apta a\n        ser regularizada em sua totalidade mediante Legitimação Fundiária através da\n        Regularização Fundiária por Interesse Social – Reurb-S (sem prejuízo de posterior indicação de regularização\n        individual dos lotes não identificados via Reurb-E), cuja área se encontra localizada\n        em área consolidada e dotada de parcial infraestrutura básica, com termo de responsabilidade do Município a\n        implementar gradualmente nos termos da Lei.</p>\n    <br>\n    <p style=\"text-align: center;\">\n        Juruaia - MG, 13 de dezembro de 2024\n    </p>\n    <p style=text-align:center>Celso Marques Junior<br>Prefeito Municipal</p>\n\n</body>\n\n</html>','crf_78801246.pdf','pdf',1,'2024-12-13 08:36:27',75,NULL,1),(5,'5828058872',2,'doc',NULL,'3927216278-doc.pdf','pdf',1,'2024-12-13 08:41:36',75,NULL,7),(6,'5828058872',7,'CRF','<!DOCTYPE html>\n<html>\n\n<head>\n    <meta charset=\"UTF-8\">\n    <title>CRF</title>\n    <style>\n        body {\n            font-family: Arial, sans-serif;\n            font-size: 12px;\n            line-height: 1.6;\n        }\n\n        h1 {\n            text-align: center;\n            color: #555555;\n        }\n\n        p {\n            text-align: justify;\n        }\n\n        i {\n            font-style: italic;\n            font-size: 11px;\n        }\n    </style>\n</head>\n\n<body>\n\n    <div style=\"text-align: center;\">\n        <img src=\"https://e-reurbsistema.com.br/sistema/v2/assets/tema/images/logo_1733236656.png\" alt=\"Logo do Município\" style=\"width: 150px; height: auto;\">\n    </div>\n\n    <h1>CERTIDÃO DE REGULARIZAÇÃO FUNDIÁRIA</h1>\n\n    <p><strong>Número do procedimento:</strong> S2024-003</p>\n    <p><strong>Modalidade:</strong> Reurb-S</p>\n    <p><strong>Tipo:</strong> COLETIVO</p>\n\n    <p>\n        Eu, <b>Celso Marques Junior</b>, inscrito no CNPF/MF sob o nº <i>000.000.000-00</i>, portador da cédula\n        de identidade Registro Geral nº <i>rg</i>, <b>Prefeito Municipal de Juruaia</b>, em pleno\n        exercício do mandato,\n        na forma da Lei e nos termos dos Artigos 30 e 41 da Lei Federal nº 13.465/2017, do Art. 38 do Decreto nº\n        9.310/2018, e Lei Complementar Municipal nº <i>99.99</i> e Decreto Municipal nº\n        <i>99</i>, <b>CERTIFICO</b> para os devidos fins de registro imobiliário, que tramitou\n        perante a Comissão Municipal de Regularização Fundiária, nomeada pelo Decreto <i>99</i>.\n        O Procedimento Administrativo Nº S2024-003 requerido pela Comissão de Regularização Fundiária\n        Urbana de Juruaia, através de sua presidente, <i>{presidente}</i>, teve início através da Portaria\n        nº <i>{portaria}</i> de <i>{dia}</i> de <i>{mes}</i> de <i>{ano}</i>, procedimento\n        ora finalizado por decisão da Comissão, emitindo o Projeto completo, conforme em anexo, que acato e defiro,\n        informando os seguintes requisitos existentes no referido procedimento:\n    </p>\n\n    <p>\n        1 - <b>Nome do núcleo:</b> Bairro Nova Resende <br>\n        2 - <b>Localização:</b> <br>\n        3 - <b>Memorial Descritivo:</b><br><i></i><br>\n        4 - <b>Modalidade da Regularização:</b> Reurb-S<br>\n        5 - <b>Projeto Técnico da Regularização:</b> Segue em anexo, assinado pelo engenheiro responsável e pela equipe\n        da Reurb Juruaia<br>\n        6 - O Núcleo informal passa a fazer parte da área urbana do município, eis que já dentro do perímetro urbano\n        conforme Lei Municipal 99<br>\n        7 - <b>Da responsabilidade das obras e serviços constantes do cronograma:</b><br>\n        Conforme certidão de cronograma na forma do Art. 41, IV da Lei 13.465/17, será do poder público municipal,\n        através de recursos próprios ou de convênios, repasses específicos\n        ou outra forma, a implementação do restante da infraestrutura faltante no núcleo, a saber, energia elétrica,\n        meio-fio, esgoto e pavimentação (podendo ser asfáltica ou outra modalidade),\n        que, considerando haver possibilidade de regularização posterior individual via Reurb-S, poderá ter auxílio dos\n        ocupantes, tudo no prazo do {§1º} do Art. {} da Lei Complementar\n        Municipal 99.99, ou programas próprios ou dos governos federal e estadual.<br>\n\n        8 - <b>Lotes Regularizados:</b> Os lotes regularizados são os que fazem parte do memorial descritivo, aprovado\n        no projeto de regularização em anexo, resumidamente a saber:<br>\n    </p>\n\n    <ul>\n        <li><b>Quadra: B</b></li>\n            <ul>\n              <li>\n                 <b>Lote: 1</b> - Proprietário(s): <b>JUSCELIO FERNANDO NOVAIS</b>\n                 <br>\n                 <b>Memorial descritivo:</b> <i>memorial</i>\n              </li>\n              <hr>\n            </ul>\n            <ul>\n              <li>\n                 <b>Lote: 2</b> - Proprietário(s): <b>JUSCELIO FERNANDO NOVAIS, PAULO CESAR PEREIRA ALVES</b>\n                 <br>\n                 <b>Memorial descritivo:</b> <i></i>\n              </li>\n              <hr>\n            </ul><li><b>Quadra: C</b></li>\n            <ul>\n              <li>\n                 <b>Lote: 1</b> - Proprietário(s): <b>JUSCELIO FERNANDO NOVAIS</b>\n                 <br>\n                 <b>Memorial descritivo:</b> <i>memorial</i>\n              </li>\n              <hr>\n            </ul>\n            <ul>\n              <li>\n                 <b>Lote: 2</b> - Proprietário(s): <b>Sem proprietário</b>\n                 <br>\n                 <b>Memorial descritivo:</b> <i>memorial</i>\n              </li>\n              <hr>\n            </ul>\n    </ul>\n\n    <br>\n    <p><b>PROPRIETÁRIOS:</b></p>\n    <p>\n        <p style=\'text-align: justify;\'><b>Proprietário:</b> JUSCELIO FERNANDO NOVAIS, CPF: 079.868.986-23, RG: {não informado}, \n        Profissão: {não informado}, Nascido em: {não informado} (menor de idade), \n        Filho de {não informado} e {não informado}, Estado Civil: Casado, \n        Residente no endereço: {não informado}, {não informado} {não informado}, \n        Bairro: {não informado}, Cidade: {não informado}, Estado: {não informado}, \n        CEP: {não informado}, Capacidade: {não informado}.</p>\n            <p style=\'text-align: justify;\'><b>Cônjuge:</b> nome do conjuge, CPF: 113.637.996-73, RG: {não informado}, \n            Profissão: {não informado}, Nascido em: {não informado} (menor de idade), \n            Filho de {não informado} e {não informado}.</p><hr>\n        <p style=\'text-align: justify;\'><b>Proprietário:</b> PAULO CESAR PEREIRA ALVES, CPF: 113.637.996-73, RG: {não informado}, \n        Profissão: {não informado}, Nascido em: {não informado} (menor de idade), \n        Filho de {não informado} e {não informado}, Estado Civil: {não informado}, \n        Residente no endereço: {não informado}, {não informado} {não informado}, \n        Bairro: {não informado}, Cidade: {não informado}, Estado: {não informado}, \n        CEP: {não informado}, Capacidade: {não informado}.</p><hr></p>\n    <br>\n\n    <p>9 - A presente Certidão vai acompanhada dos seguintes documentos: Projeto da\n        Regularização, Memorial descritivo\n        das Quadras, Mapas geográficos, 1 via do ART e principais\n        documentos do processo administrativo.</p>\n\n    <p>10 - Conforme Art. 22, §6º da Lei 13.465/17, a área remanescente da matrícula do\n        imóvel atingido deve ser apurada\n        e realizada a retificação por responsabilidade de seus proprietários.</p>\n\n    <p>11 - Conclui-se, portanto, e certifico que a poligonal parcial definida como\n        \"Bairro Nova Resende\" está apta a\n        ser regularizada em sua totalidade mediante Legitimação Fundiária através da\n        Regularização Fundiária por Interesse Social – Reurb-S (sem prejuízo de posterior indicação de regularização\n        individual dos lotes não identificados via Reurb-E), cuja área se encontra localizada\n        em área consolidada e dotada de parcial infraestrutura básica, com termo de responsabilidade do Município a\n        implementar gradualmente nos termos da Lei.</p>\n    <br>\n    <p style=\"text-align: center;\">\n        Juruaia - MG, 24 de fevereiro de 2025\n    </p>\n    <p style=text-align:center>Celso Marques Junior<br>Prefeito Municipal</p>\n\n</body>\n\n</html>','crf_49387840.pdf','pdf',1,'2025-02-24 17:54:22',75,NULL,3),(7,'6715014974',1,'PARECER',NULL,'3530377078-PARECER.docx','docx',1,'2025-02-25 09:44:34',20,NULL,5),(8,'6715014974',4,'MORIAIS',NULL,'847844529-MORIAIS.docx','docx',0,'2025-02-25 10:12:36',20,NULL,4),(9,'6715014974',2,'ESTUDO PRELIMINAR',NULL,'2198514579-ESTUDO_PRELIMINAR.pdf','pdf',1,'2025-02-25 10:19:15',20,NULL,3),(10,'6715014974',2,'MATRICULAS',NULL,'2605166915-MATRICULAS.pdf','pdf',1,'2025-02-25 10:19:45',20,NULL,2),(11,'6715014974',6,'PROJETO','<!DOCTYPE html>\n<html>\n\n<head>\n    <meta charset=\"UTF-8\">\n    <title>PROJETO</title>\n    <style>\n        body {\n            font-family: Arial, sans-serif;\n            font-size: 12px;\n            line-height: 1.6;\n        }\n\n        h1 {\n            text-align: center;\n            color: #555555;\n        }\n\n        p {\n            text-align: justify;\n        }\n\n        i {\n            font-style: italic;\n            font-size: 11px;\n        }\n    </style>\n</head>\n\n<body>\n\n    <div style=\"text-align: center;\">\n        <img src=\"https://e-reurbsistema.com.br/sistema/v2/assets/tema/images/logo_1733236656.png\" alt=\"Logo do Município\" style=\"width: 150px; height: auto;\">\n    </div>\n    <br>\n