CREATE TABLE `tb_localidade` (
  `loca_id` int(11) NOT NULL AUTO_INCREMENT,
  `loca_uf` varchar(15) DEFAULT NULL,
  `loca_codigo_municipio` int(255) DEFAULT NULL,
  `loca_nome_municipio` varchar(80) DEFAULT NULL,
  `loca_cep` int(1) DEFAULT NULL,
  `loca_ibge` varchar(20) DEFAULT NULL,
  `loca_status` int(11) DEFAULT '1',
  PRIMARY KEY (`loca_id`)
) ENGINE=InnoDB AUTO_INCREMENT=10890 DEFAULT CHARSET=utf8mb4 ROW_FORMAT=DYNAMIC;

