#
# Structure for table "tipos_documentos"
#

CREATE TABLE `tipos_documentos` (
  `tipo_id` int(11) NOT NULL AUTO_INCREMENT,
  `tipo_nome` varchar(255) NOT NULL,
  `tipo_descricao` text,
  PRIMARY KEY (`tipo_id`)
) ENGINE=InnoDB AUTO_INCREMENT=4 DEFAULT CHARSET=utf8mb4;

#
# Data for table "tipos_documentos"
#

INSERT INTO `tipos_documentos` VALUES (1,'Procuração','Documento que concede poderes a outra pessoa para agir em seu nome'),(2,'Certidão Negativa de Bens','Documento que comprova a inexistência de bens em nome do solicitante'),(3,'Comprovante de Residência','Documento que atesta o endereço do solicitante');

#
# Structure for table "users"
#

CREATE TABLE `users` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `id_permission` int(11) DEFAULT NULL,
  `user_municipio` int(11) DEFAULT NULL,
  `email` varchar(255) COLLATE utf8_unicode_ci NOT NULL,
  `password` varchar(100) COLLATE utf8_unicode_ci NOT NULL,
  `name` varchar(255) COLLATE utf8_unicode_ci DEFAULT NULL,
  `admin` int(1) DEFAULT '0',
  `status` int(1) DEFAULT '1',
  `token` varchar(255) COLLATE utf8_unicode_ci DEFAULT NULL,
  `recuperar_senha` varchar(255) COLLATE utf8_unicode_ci DEFAULT NULL,
  `data` varchar(20) COLLATE utf8_unicode_ci DEFAULT NULL,
  `data_update` varchar(20) COLLATE utf8_unicode_ci DEFAULT NULL,
  PRIMARY KEY (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=115 DEFAULT CHARSET=utf8 COLLATE=utf8_unicode_ci ROW_FORMAT=DYNAMIC;

